package com.example.sharehandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class ShareHandlerActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share_handler)

        handleIncomingShareIntent(intent)
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleIncomingShareIntent(intent)
    }

    private fun handleIncomingShareIntent(intent: Intent) {
        if (intent.action == Intent.ACTION_SEND || intent.action == Intent.ACTION_SEND_MULTIPLE) {
            val type = intent.type
            if (type != null) {
                when {
                    type.startsWith("text/") -> handleText(intent)
                    type.startsWith("image/") -> handleImages(intent)
                    else -> showToast("Unsupported content type")
                }
            }
        }
    }

    private fun handleText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        if (sharedText != null && isValidUrl(sharedText)) {
            // Process the URL
            showToast("Received URL: $sharedText")
        } else {
            showToast("Invalid or no URL received")
        }
    }

    private fun handleImages(intent: Intent) {
        val imageUris = mutableListOf<Uri>()
        if (intent.action == Intent.ACTION_SEND) {
            intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)?.let { imageUris.add(it) }
        } else if (intent.action == Intent.ACTION_SEND_MULTIPLE) {
            intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)?.let { imageUris.addAll(it) }
        }

        if (imageUris.isNotEmpty()) {
            // Process the images
            showToast("Received ${imageUris.size} images")
        } else {
            showToast("No images received")
        }
    }

    private fun isValidUrl(url: String): Boolean {
        return android.util.Patterns.WEB_URL.matcher(url).matches()
    }

    private fun showToast(message: String) {
        Toast.makeText(this, message, Toast.LENGTH_SHORT).show()
    }
}